import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"72. Long Service Leave","description":"","frontmatter":{"title":"72. Long Service Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","long-service-leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/leave/72-long-service-leave.md","filePath":"ebas/allied-health/leave/72-long-service-leave.md"}'),r={name:"ebas/allied-health/leave/72-long-service-leave.md"};function i(s,e,l,p,c,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_72-long-service-leave" tabindex="-1">72. Long Service Leave <a class="header-anchor" href="#_72-long-service-leave" aria-label="Permalink to &quot;72. Long Service Leave&quot;">​</a></h1><p><strong>72.1</strong> Scope This clause 72 is split into four (4) parts:</p><p><strong>(a)</strong> Part 1 (subclauses 72.1 - 72.2) explains the scope of this clause 72 and includes defined terms used across each Part.</p><p><strong>(b)</strong> Part 2 (subclauses 72.3 - 72.10) sets out the long service leave entitlement of non-casual Employees (full-time and part-time, including fixed-term), as well as casual Dental Prosthetists and Dental Technicians, at the time they take a period of long service leave or their employment ceases.</p><p><strong>(c)</strong> Part 3 (subclauses 72.11 - 72.18) sets out the long service leave entitlement of casual Employees (other than casual Dental Prosthetists or Dental Technicians) at the time they take a period of long service leave or their employment ceases.</p><p><strong>(d)</strong> Part 4 (subclauses 72.19 - 72.23) contains a series of common provisions that apply in respect of all Employees.</p><p><strong>72.2</strong> Definitions The following meanings shall apply to the terms referred to below for the purposes of this clause 72 unless a contrary intention is apparent:</p><p><strong>(a)</strong> Allowable Period of Absence means five (5) weeks in addition to the total period of paid annual, long service and/or personal leave which the Employee actually receives on termination or for which the Employee is paid in lieu.</p><p><strong>(b)</strong> Institution means any employer, health service, hospital or benevolent home, community health centre, society or association:</p><p><strong>(i)</strong> named in <a href="/eba/ebas/allied-health/appendices/1-list-of-employers.html">Appendix 1</a> of this Agreement;</p><p><strong>(ii)</strong> that was created or registered under the Health Services Act 1988 (Vic) or the former Hospital and Charities Act 1958 (Vic); or</p><p><strong>(iii)</strong> the Cancer Institute constituted under the Cancer Act 1958 (Vic);</p><p><strong>(iv)</strong> and successors thereto.</p><p><strong>(c)</strong> LSL Act means the Long Service Leave Act 2018 (Vic).</p><p><strong>(d)</strong> Month means a calendar month.</p><p><strong>(e)</strong> Pay means remuneration for an Employee’s normal weekly hours of work calculated at the Employee’s ordinary time rate of pay provided in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> at the time the leave is taken or (if the Employee dies before the completion of leave so taken) as at the time of the Employee&#39;s death, and will include the amount of any increase to the Employee’s ordinary time rate of pay which occurred during the period of leave as from the date of such increase operates. Where a part-time Employee&#39;s hours fluctuate because the Employee works additional ordinary shifts (but excluding a permanent variation), the &#39;normal weekly hours of work&#39; will be calculated by taking an average over the preceding 12 months where this is more favourable to the Employee.</p><p><strong>(f)</strong> Pay for a casual Employee means the remuneration for the Employee’s normal weekly hours of work at their ordinary pay calculated in accordance with sections 15 and 16 of the LSL Act.</p><p><strong>(g)</strong> Service means employment with an employer, Institution or Statutory Body.</p><p><strong>(h)</strong> Statutory Body means the Hospital and Charities Commission of Victoria, the Health Commission of Victoria, and/or the Victorian Nursing Council and Successors.</p><p><strong>(i)</strong> Transfer of business occurs in the circumstances described at section 311 of the Act.</p><p>DENTAL PROSTHETISTS AND DENTAL TECHNICIANS)</p><p><strong>72.3</strong> Application of Part 2 This Part 2 (clauses 72.3 - 72.10) applies to non-casual Employees, casual Dental Prosthetists, and casual Dental Technicians only.</p><p><strong>72.4</strong> Entitlement</p><p><strong>(a)</strong> Subject to subclause 72.6, Employees are entitled to:</p><p><strong>(i)</strong> six (6) months&#39; long service leave with Pay on completion of fifteen years&#39; Continuous Service; and</p><p><strong>(ii)</strong> thereafter an additional two (2) months&#39; long service leave with Pay on completion of each additional five (5) years of Continuous Service.</p><p><strong>(b)</strong> Subject to subclause 72.6(c) and (d), an entitlement under subclause 72.4(a)(i) may be taken in advance on a pro rata basis if the Employee has accrued Continuous Service of at least:</p><p><strong>(i)</strong> 10 years;</p><p><strong>(ii)</strong> from 1 July 2021, 9 years;</p><p><strong>(iii)</strong> from 1 July 2022, 8 years; or</p><p><strong>(iv)</strong> from 1 July 2023, 7 years.</p><p><strong>72.5</strong> Calculating Continuous Service</p><p><strong>(a)</strong> Definitions:</p><p><strong>(i)</strong> Continuous Service means continuous Service with the same employer plus any prior Service of six (6) months or more with one (1) or more Institutions or Statutory Bodies.</p><p><strong>(ii)</strong> Continuous Casual Employment means, for the purpose of subclause 72.5(b), a period or periods of casual Service that are taken to be continuous, because one of the following applies: A. the period starting at the end of a particular instance of employment and ending at the start of another particular instance of employment did not exceed either the Allowable Period of Absence, or 12 weeks (whichever is greater); B. the Employee had been employed by an employer on a regular and systematic basis and the Employee had a reasonable expectation of being re-engaged by the same employer; C. the gap between engagements was due to the terms of engagement of the casual Employee; D. the gap between engagements was caused by seasonal factors; or E. the Employee and employer agreed, before the start of an absence, to treat the employment as continuous despite the</p><p>absence.</p><p><strong>(b)</strong> Periods that count towards Continuous Service Service or prior Service during the following periods will be deemed to be continuous and will count as Continuous Service for the purpose of subclause 72.5(a):</p><p><strong>(i)</strong> an absence from work on any form of paid leave (e.g. annual leave, personal leave, long service leave and paid parental leave);</p><p><strong>(ii)</strong> any interruption or ending of employment by the employer if made with the intention of avoiding obligations in respect of long service leave or annual leave;</p><p><strong>(iii)</strong> any absence on account of illness or injury arising out of or in the course of the employment for a period during which an Employee is receiving accident pay (see <a href="/eba/ebas/allied-health/wages/32-accident-pay.html">clause 32</a>);</p><p><strong>(iv)</strong> any absence from employment on defence service in accordance with</p><p><strong>(v)</strong> a period of absence on community service leave under the Act;</p><p><strong>(vi)</strong> in the case of unpaid absences not otherwise referenced in this subclause 72.5(b), subject to clause 72.10, as follows: A. any unpaid leave that is authorised in advance in writing by the employer to count as service; or B. up to (and including) 6 July 2022, any unpaid absence from work of not more than fourteen days in any year on account of illness or injury; or C. on and from 7 July 2022: (1) any period of unpaid leave taken on account of illness or injury; (2) a period of Parental Leave, including Parental Leave that is extended under subclause 70.14; and (3) the first 52 weeks of any other type of unpaid leave not specifically referenced in this subclause 72.5(b)(vi); and</p><p><strong>(vii)</strong> periods of Continuous Casual Employment with an employer, Statutory Body or Institution; save that if long service leave was already taken or paid in lieu in respect of any such period, no further benefit to take long service leave will arise in respect of that period.</p><p><strong>(c)</strong> Periods that do not break Continuous Service, but do not count towards Continuous Service Unless otherwise agreed in writing between the employer and Employee, the following periods do not break Continuous Service but do not count towards an</p><p>Employee&#39;s Continuous Service for the purpose of calculating the Employee&#39;s long service leave entitlement:</p><p><strong>(i)</strong> any authorised period of absence on unpaid leave not referred to in subclause 72.5(b);</p><p><strong>(ii)</strong> subject to the requirements of the Act, any interruption arising directly or indirectly from an industrial dispute;</p><p><strong>(iii)</strong> any period between the employment with one Institution or Statutory Body and another provided it is equal to or less than the Allowable Period of Absence from employment;</p><p><strong>(iv)</strong> the dismissal of an Employee if the Employee is re-employed by the same employer within a period not exceeding two (2) months from the date of such dismissal;</p><p><strong>(v)</strong> up to (and including) 6 July 2022, any absence on account of injury arising out of or in the course of their employment not covered by a period in which an Employee is receiving accident make up pay or other paid leave;</p><p><strong>(vi)</strong> any absence from work for a period not exceeding twelve months in respect of any pregnancy or adoption not covered by subclause 72.5(b)(i) or (vi).</p><p><strong>(d)</strong> Effect of taking or being paid in lieu long service leave on an Employee’s commencement date For the removal of doubt, where an Employee has received long service leave or payment in lieu of long service leave from an Institution or Statutory Body (including an employer covered by this Agreement), this does not alter the Employee’s commencement date for the purpose of calculating the Employee’s total period of Continuous Service.</p><p>Example: An Employee, upon reaching 15 years’ service with employer A, resigns. The Employee receives payment in lieu of the six (6) months’ Long Service Leave (LSL) that had accrued. Within the Allowable Period of Absence, the Employee commences employment with employer B. The 15 years’ service with employer A counts as service with employer B for the purposes of LSL. The Employee is entitled to two (2) months’ LSL after five (5) years’ service with employer B. The Employee is not entitled to any further benefit for the period of service with employer A.</p><p><strong>72.6</strong> Taking of leave</p><p><strong>(a)</strong> When leave is to be taken Long service leave will be granted by the employer within six (6) months from the date of the entitlement arising under subclause 72.4(a) save that:</p><p><strong>(i)</strong> long service leave may be postponed to a mutually agreeable date;</p><p><strong>(ii)</strong> if agreement cannot be reached: A. where the Employee is employed in one of the following</p><p>professions, they may nominate preferred date(s) for the taking of leave, save that the employer may refuse the date(s) so nominated on reasonable business grounds: (1) Art Therapist; (2) Exercise Physiologist; (3) Play Therapist (Child Life Therapist); (4) Mechanical Officer; or (5) Radiation Engineer; or B. for all other Employees, the date will be determined by a member of the Commission provided that such a determination will not require long service leave to commence before six (6) months from the date of such determination; and</p><p><strong>(iii)</strong> leave the subject of approval or grant under subclause 72.6(c) shall be taken in accordance with the terms of the application or agreement.</p><p><strong>(b)</strong> How leave is to be taken Long service leave may be taken:</p><p><strong>(i)</strong> in any number of periods, with each period being no less than one (1) week, or where administratively possible one (1) day, as agreed between the Employee and the employer; or</p><p><strong>(ii)</strong> where it is taken as part of a transition to retirement, in any other way agreed upon by the employer and Employee.</p><p><strong>(c)</strong> Long service leave in advance</p><p><strong>(i)</strong> If an Employee has completed ten years&#39; Continuous Service, an employer may, by agreement with the Employee, grant long service leave in advance on a pro rata basis.</p><p><strong>(ii)</strong> Supplementary to subclause 72.6(c)(i), and subject to subclause 72.6(c)(iii), if an Employee requests to take long service leave on a pro rata basis under clause 72.4(b), the employer must grant the Employee&#39;s request to take long service leave as soon as practicable after receiving the request unless the employer has reasonable business grounds for refusing the request.</p><p><strong>(iii)</strong> In the event of a dispute over when the leave in subclause 72.6(c)(ii) is to be taken, the dispute resolution procedure at <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> will apply.</p><p><strong>(d)</strong> Flexible taking of leave</p><p><strong>(i)</strong> An Employee may, subject to subclause 72.6(d)(iv), request to take double the period of long service leave at half Pay.</p><p><strong>(ii)</strong> Employees should seek independent advice regarding the taxation and superannuation implications of seeking payment under this subclause 72.6(d). The employer will not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>(iii)</strong> The employer, if requested by the Employee, will provide information as to the amount of tax the employer intends to deduct where payment of long service leave is sought under subclause 72.6(d)(i).</p><p><strong>(iv)</strong> Wherever it is practical to do so, the employer will grant a request by an Employee under subclause 72.6(d)(i). If granting the request under this subclause 72.6(d)(iv) would result in an additional cost to the employer, then it is not practical to grant an Employee’s request.</p><p><strong>(v)</strong> Flexible taking of long service leave does not affect an Employee&#39;s continuous service recognised.</p><p>Example: In the case of an Employee taking 12 months&#39; paid long service leave at half pay, six (6) months will count towards the Employee&#39;s Continuous Service (and the remaining six (6) months will not break continuity of service).</p><p><strong>72.7</strong> Payment on termination of employment</p><p><strong>(a)</strong> Basic entitlement at termination of employment Except where an election is made under clause 72.7(b) below, an Employee is entitled to payment in lieu of untaken long service leave upon termination of employment (calculated at one thirtieth of the period of Continuous Service) if, as at the termination date:</p><p><strong>(i)</strong> the Employee has accrued at least fifteen years&#39; Continuous Service; or</p><p><strong>(ii)</strong> the Employee has an entitlement to take pro rata long service leave in advance under subclause 72.4(b).</p><p><strong>(b)</strong> Election for payment of entitlement or transfer of entitlement at termination</p><p><strong>(i)</strong> This subclause 72.7(b) applies to Employees who intend to be re- employed by another employer, Institution or Statutory Body, and: A. are entitled to take pro rata long service leave in advance under subclause 72.4(b); or B. in the case of the following classifications, have otherwise accrued at least seven (7) years’ Continuous Service with their employer: (1) Art Therapist; (2) Exercise Physiologist; (3) Play Therapist (Child Life Therapist); (4) Mechanical Officer; or (5) Radiation Engineer.</p><p><strong>(ii)</strong> An Employee to whom subclause 72.7(b)(i) applies may: A. request in writing that payment for accrued long service leave be deferred until after the Employee’s Allowable Period of</p><p>Absence (as defined above) has expired; and B. where the Employee notifies the initial employer in writing within the Allowable Period of Absence that the Employee has been employed by such an employer, and the re-employment meets the criteria set out in in subclause 72.7(b)(iv) below, the initial employer is no longer required to make payment to the Employee in respect of such service.</p><p><strong>(iii)</strong> Where the notice referred to at subclause 72.7(b)(ii)B. is not provided to the initial employer prior to or within the Allowable Period of Absence (including because the re-employment does not meet the criteria set out in in subclause 72.7(b)(iv) below, the initial employer will, upon the expiration of the Allowable Period of Absence, make payment in lieu of long service leave as per subclause 72.7(a).</p><p><strong>(iv)</strong> For the purposes of this subclause 72.7(b), re-employment by another employer, Institution or Statutory Body means employment other than as a casual Employee (except as a casual Dental Prosthetist or casual Dental Technician).</p><p><strong>(c)</strong> For the removal of doubt:</p><p><strong>(i)</strong> where an Employee has accrued at least fifteen years&#39; Continuous Service with an employer, this cannot be transferred and the Employee will receive payment in lieu of untaken long service leave upon termination of employment; and</p><p><strong>(ii)</strong> an Employee is able to transfer Service where they do not have the amount of Continuous Service required in accordance with subclause 72.7(b)(i).</p><p><strong>(d)</strong> Payment in lieu of long service leave on the death of an Employee Where an Employee dies while still in the employ of the employer, payment in lieu of long service leave will be made to the Employee’s personal representative in accordance with subclause 72.7(a) above.</p><p><strong>(e)</strong> No entitlement arising for periods of leave already taken For the removal of doubt, where an Employee makes an election under subclause 72.7(b) such that their previous Service is recognised by the new employer, the Employee’s previous employer is no longer liable to make any payment in lieu of that Employee’s Service (unless the Employee makes a subsequent election, under subclause 72.7(b) above, to transfer their Service back to their previous employer).</p><p><strong>72.8</strong> Public holidays and Accrued Days Off See also <a href="/eba/ebas/allied-health/leave/58-public-holidays.html">clause 58</a> (Public Holidays) and 48 (Accrued Days Off). Long service leave is inclusive of any public holiday or ADO occurring during the period when leave is taken.</p><p><strong>72.9</strong> Proof of sufficient aggregate of service</p><p><strong>(a)</strong> The onus of proving a sufficient aggregate of service to support a claim for any long service leave entitlement will at all times rest upon the Employee concerned. A Certificate of Service in accordance with <a href="/eba/ebas/allied-health/appendices/6-certificate-of-service.html">Appendix 6</a> or a similar form will constitute acceptable proof.</p><p><strong>(b)</strong> An employer will provide an Employee whose employment is ending with a Certificate of Service in accordance with <a href="/eba/ebas/allied-health/appendices/6-certificate-of-service.html">Appendix 6</a> upon request.</p><p><strong>(c)</strong> Upon request by an Employee who is entitled to Long Service Leave in accordance with this clause 72, an employer must provide to the Employee a Certificate of Service in accordance with <a href="/eba/ebas/allied-health/appendices/6-certificate-of-service.html">Appendix 6</a> or a similar form if the Employee will continue to be employed as a casual Employee by the employer.</p><p><strong>72.10</strong> Transitional Arrangements for Parental Leave taken after 1 November 2018 and before 7 July 2022 Note 1: Unpaid Parental Leave taken prior to 1 November 2018 does not count as Continuous Service unless otherwise agreed, per subclause 72.5(b)(vi)A. Note 2: Unpaid Parental Leave taken after 6 July 2022 will constitute Continuous Service, per subclause 72.5(b)(vi)C.(2).</p><p><strong>(a)</strong> As an exception to clause 72.5(b), an Employee who took a period of unpaid Parental Leave that included any part of the period between 1 November 2018 and 6 July 2022 (inclusive) may make an application to the employer to have that service recognised for Long Service Leave purposes. The employer will approve the application and provide to the Employee an updated Certificate of Service reflecting the adjusted service arrangements.</p><p><strong>(b)</strong> An Employee electing to make an application under subclause 72.10(a) must make the application to the employer no later than six (6) months of the following (whichever occurs last):</p><p><strong>(i)</strong> the date on which this Agreement commences; or</p><p><strong>(ii)</strong> the date on which the Employee returns to work after the qualifying period of unpaid Parental Leave.</p><p><strong>(c)</strong> This subclause 72.10 shall also apply to an Employee in respect of a former employer if the Employee took a qualifying unpaid period of Parental Leave under subclause 72.10(a) while employed by that former employer. DENTAL PROSTHETISTS AND DENTAL TECHNICIANS)</p><p><strong>72.11</strong> Application of Part 3 Casual Employees (other than casual Dental Prosthetists and Dental Technicians) shall be entitled to long service leave with ordinary pay in accordance with this Part 3 (clauses 72.11 - 72.18).</p><p><strong>72.12</strong> Interpretation For the purposes of this Part 3:</p><p><strong>(a)</strong> Continuous employment has the meaning given in sections 12-14 and 57 of the LSL Act;</p><p><strong>(b)</strong> Normal weekly hours has the meaning given in sections 16 and 17 of the LSL Act;</p><p><strong>(c)</strong> One employer has the meaning given in section 11 of the LSL Act; and</p><p><strong>(d)</strong> Ordinary pay has the meanings given in sections 15, 17 and 21 of the LSL Act.</p><p><strong>72.13</strong> Entitlement At any time after completing seven (7) years of continuous employment with one (1) employer, an Employee is entitled to an amount of long service leave on ordinary pay equal to 1/60th of the Employee&#39;s total period of continuous employment less any period of long service leave taken during that period.</p><p><strong>72.14</strong> Taking of leave</p><p><strong>(a)</strong> When leave is to be taken In accordance with s.18(2) of the LSL Act, an employer must grant an Employee&#39;s request to take long service leave as soon as practicable after receiving the request unless the employer has reasonable business grounds for refusing the request.</p><p><strong>(b)</strong> How leave is to be taken In accordance with s.18(1) of the LSL Act, an Employee may request to take long service leave for a period of not less than one (1) day.</p><p><strong>(c)</strong> Long service leave in advance</p><p><strong>(i)</strong> Subject otherwise to this Part 3 and in accordance with s.8(1) of the LSL Act, an employer may agree to an Employee taking long service leave prior to them completing seven (7) years of continuous employment and at any time before they become entitled to long service leave.</p><p><strong>(ii)</strong> If an Employee takes long service leave in advance and the Employee&#39;s employment ends before the entitlement to the leave would otherwise have accrued: A. the amount paid for the proportion of leave to which the Employee will not become entitled becomes an amount owed by the Employee to the employer; B. the employer may deduct this amount from any payment owed to the Employee as a result of the ending of employment; and C. the relevant period of service will not count as a period in respect of which long service leave has already been taken (or paid in lieu) for the purpose of calculating any future entitlement to long service leave.</p><p><strong>(d)</strong> Flexible taking of leave: double leave at half pay</p><p><strong>(i)</strong> An Employee may request an employer to take double the period of long service leave at half pay.</p><p><strong>(ii)</strong> An employer must grant such a request unless: A. granting the request would result in an additional cost to the</p><p>employer; or B. the employer otherwise has reasonable business grounds for refusing the request.</p><p><strong>(iii)</strong> Employees should seek independent advice regarding the taxation and superannuation implications of seeking payment under this subclause 72.14(d). The employer will not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>(iv)</strong> The employer, if requested by the Employee, will provide information as to the amount of tax the employer intends to deduct where payment of long service leave is sought under this subclause.</p><p><strong>72.15</strong> Payment on termination of employment</p><p><strong>(a)</strong> Basic entitlement at termination of employment An Employee with at least seven (7) years continuous employment is entitled to payment in lieu of untaken long service leave upon termination of employment, calculated at 1/60th of the period of continuous employment.</p><p><strong>(b)</strong> Payment in lieu of long service leave on the death of an Employee Where an Employee has completed at least seven (7) years’ continuous employment and dies while still in the employ of the employer, payment in lieu of long service leave will be made to the Employee’s personal representative equal to that in subclause 72.15(a) above.</p><p><strong>72.16</strong> Public holidays &amp; Annual leave Long service leave does not include any public holiday occurring during the period when the long service leave is taken.</p><p><strong>72.17</strong> No entitlement arising for periods of leave already taken or transferred For the removal of doubt, no entitlement to long service leave (or payment in lieu) arises in respect of:</p><p><strong>(a)</strong> continuous employment for which long service leave has already been taken or payment in lieu of leave has been received; and/or</p><p><strong>(b)</strong> prior service as a full-time or part-time Employee that is transferred to a new employer in accordance with subclause 72.7(b) above (see subclause 72.22(c) for how this operates when an Employee remains a casual Employee with their previous employer). Example: An Employee resigns after five (5) years’ part-time service with employer A. The Employee remains a casual Employee with employer A. The Employee requests a Certificate of Service in accordance with <a href="/eba/ebas/allied-health/appendices/6-certificate-of-service.html">Appendix 6</a> or a similar form from employer A, which is provided to the Employee. Within the Allowable Period of Absence (as defined above), the Employee commences full-time employment with employer B and provides the Certificate of Service provided to them by employer A to employer B, indicating they have five (5) years’ service.</p><p>After five (5) years’ service with employer B, the Employee wishes to take LSL. As the Employee has 10 years’ service with employer B for the purposes of LSL (five (5) years of which is service that was accrued with employer A), the Employee is entitled to access long service leave in accordance with subclause 72.4(b).</p><p>Although the five (5) years of service the Employee had at employer A will still count as service for the Employee’s casual entitlement to long service leave with employer A, no further benefit to long service leave may arise in respect of that 5 year period (unless the Employee subsequently makes a further election to transfer the relevant period of service back to employer A).</p><p><strong>72.18</strong> Other terms and conditions necessary for this Part Any other term or condition necessary for the operation of this Part 3 shall be in accordance with the applicable term or condition in the LSL Act.</p><p><strong>72.19</strong> Payment for period of leave</p><p><strong>(a)</strong> Payment will be made in one (1) of the following ways:</p><p><strong>(i)</strong> in full advance when the Employee commences their leave;</p><p><strong>(ii)</strong> at the same time as payment would have been made if the Employee had remained on duty; or</p><p><strong>(iii)</strong> in any other way agreed between the employer and the Employee.</p><p><strong>(b)</strong> Where an Employee has been paid in advance, and an increase occurs in the ordinary time rate of pay during the period of long service leave taken, the Employee will be entitled to receive payment of the amount of any increase in pay at the completion of such leave.</p><p><strong>72.20</strong> Records The employer will keep a long service leave record for each Employee, containing particulars of service, leave taken and payments made.</p><p><strong>72.21</strong> Transfer of business Where a Transfer of Business occurs, an Employee who worked with the old employer and who continues in the service of the new employer will be entitled to count their service with the old employer as service with the new employer for the purposes of this clause 72.</p><p><strong>72.22</strong> Concurrent Service</p><p><strong>(a)</strong> Subject to subclause 72.22(b), concurrent service with two (2) or more employers remains separate and distinct.</p><p><strong>(b)</strong> If a non-casual Employee transfers from an employer (the first employer) to another employer (the new employer) into a non-casual role, but retains concurrent employment with the first employer as a casual Employee, then the</p><p>Employee&#39;s service with the first employer will transfer to the new employer (despite the Employee remaining employed with the first employer), if:</p><p><strong>(i)</strong> the Employee has less than fifteen years’ Continuous Service;</p><p><strong>(ii)</strong> the Employee has an entitlement to take pro rata long service leave in advance under subclause 72.4(b); and</p><p><strong>(iii)</strong> either: A. the Employee notifies the first employer of the transfer in accordance with sub-clause 72.7(b) (Election for payment of entitlement or transfer of entitlement at termination); or B. the new employer otherwise confirms in writing to the first employer that the period of service has been so recognised (for the removal of doubt, if the new employer determines to recognise the Employee&#39;s service with the first employer, it must provide written notification of its determination to the first employer).</p><p><strong>(c)</strong> If an Employee&#39;s long service leave entitlement is transferred in accordance with subclause 72.22(b):</p><p><strong>(i)</strong> the first employer will no longer be liable for the non-casual service, and the long service leave liability for the non-casual service with the first employer will transfer to the new employer;</p><p><strong>(ii)</strong> any casual service that occurs with the first employer after the transfer referred to in subclause 72.22(c)(i) above will be considered separate and distinct service on and from the date on which the Employee commenced employment with the new employer, provided that: A. the qualifying period required to accrue an entitlement to long service leave with the first employer does not reset (that is, the Employee&#39;s prior service with the first employer can be counted when calculating any future entitlement to long service leave with the first employer); B. no benefit to long service leave will arise with the first employer in respect of the prior period of employment with the first employer (unless the Employee subsequently makes a further election to transfer the relevant period of service back to the first employer); and C. the Employee&#39;s prior service with the first employer is disregarded when calculating the Employee&#39;s normal weekly hours with the first employer as a casual Employee (e.g. for the purpose of sections 16 and 17 of the LSL Act).</p><p><strong>(iii)</strong> If the Employee is not entitled to transfer their service from the first employer to the new employer, or does not take the steps required in subclause 72.7(b) within the allowable period of absence, the first employer will make payment in lieu of long service leave for the</p><p>Continuous Service with the first employer in accordance with subclause 72.7(a) (Basic entitlement at termination of employment).</p><p><strong>(d)</strong> For the removal of doubt:</p><p><strong>(i)</strong> where an Employee has accrued at least fifteen years&#39; Continuous Service with an employer, this cannot be transferred and the Employee will receive payment in lieu of untaken long service leave upon termination of employment; and</p><p><strong>(ii)</strong> an Employee is able to transfer Service where they do not have the amount of Continuous Service required in accordance with subclause 72.22(b)(ii). Example 1: A Fulltime Employee is employed at the same time by employer 1, and employer 2. The Employee accrues service towards long service leave at each of employer 1 and employer 2. If the Employee had been employed by employer 1 for 11 years and employer 2 for six (6) years, the Employee can take LSL with employer 1, but in order to take LSL with employer 2, would need to continue working at employer 2 until sufficient Continuous Service with employer 2 had accrued. If the Employee resigned from both employer 1 and employer 2, and went to work for employer 3, the Employee could:</p><p><strong>(a)</strong> transfer the six (6) years&#39; service with employer 2 to employer 3; and</p><p><strong>(b)</strong> have the accrued LSL from the 11 years&#39; service with employer 1 paid out in lieu on termination.</p><p>Example 2: A Part-time Employee has worked for employer 1 for six (6) years. The Employee commences employment with employer 2 as a full-time Employee. To take up this opportunity, the Employee ceases permanent employment with employer 1. However, the Employee commences a casual employment relationship with employer 1 within 12 weeks after resigning from their permanent position with employer 1. The Employee:</p><p><strong>(a)</strong> could transfer the six (6) years&#39; service with employer 1 to employer 2, and would be eligible to take LSL with employer 2 once sufficient Continuous Service had accrued (taking into account the transferred service); and</p><p><strong>(b)</strong> would be entitled to take pro-rata LSL with employer 1 after a further year of Continuous Service (so they have seven (7) years’ Continuous Service), though their six (6) years’ Continuous Service as a part-time Employee will not be counted when calculating the Employee’s long service leave entitlement.</p><p><strong>72.23</strong> Savings</p><p><strong>(a)</strong> Clauses 72.7(b), 72.7(e), and 72.22(b) shall not apply to the following classifications unless the Industrial Division of the Magistrates Court provides an opinion that determines generally the rights of these Employees under sub- this Agreement are more favourable than those provided by the LSL Act:</p><p><strong>(i)</strong> Art Therapists;</p><p><strong>(ii)</strong> Exercise Physiologists;</p><p><strong>(iii)</strong> Play Therapist (Child Life Therapists);</p><p><strong>(iv)</strong> Mechanical Officers; or</p><p><strong>(v)</strong> Radiation Engineers.</p><p><strong>(b)</strong> The Unions and VHIA will make an application to the Magistrates Court under as reasonably practicable after the Agreement has been approved by the Commission.</p><p><strong>(c)</strong> No Employee shall otherwise suffer any detriment as a result of the operation of this clause 72 to their entitlement to long service leave existing immediately prior to the coming into force of this clause 72.</p><p>Plain language terms: LSL.</p>',167)])])}const d=t(r,[["render",i]]);export{u as __pageData,d as default};
